proof fn test1(n: nat) {
    assert(n as int == n as int + 0 == 0 + n as int);
    assert(2 == 1 + 1 == 3 - 1 < 4);
    assert(n as int == (n as int) * 1 == (n as int) * 1 == 1 * (n as int));
    assert(1 + n as int == n as int + 1 == 1); // FAILS
}

